    const min1 = 1;
    const max1 = 10;
    for (let i = 0; i < samples; i++) {
      const num = rng.randomInt(min1, max1);
      expect(num).toBeGreaterThanOrEqual(min1);
      expect(num).toBeLessThanOrEqual(max1);
      expect(Number.isInteger(num)).toBe(true);
    }

    // Test negative range
    const min2 = -5;
    const max2 = 5;
    for (let i = 0; i < samples; i++) {
